<script setup lang="ts">import{ref}from'vue';import{useRoute}from'vue-router';import{ElMessage}from'element-plus';import{api}from'../api';const pid=String(useRoute().params.projectId),kind=ref('teacher'),working=ref(false),job=ref<any>();async function start(){working.value=true;try{job.value=await api.createExport(pid,kind.value);for(let i=0;i<20;i++){await new Promise(r=>setTimeout(r,600));job.value=await api.exportStatus(job.value.job_id);if(['succeeded','failed'].includes(job.value.status))break}if(job.value.status==='failed')ElMessage.error(job.value.error_message)}catch(e){ElMessage.error((e as Error).message)}finally{working.value=false}}</script>
<template><section><div class="page-head"><div><h2>导出备课成果</h2><p>教师包保留教学依据与答案；学生包自动隐藏讲稿、答案和解析。</p></div></div><div class="panel panel-pad"><div class="export-choice"><article :class="['choice',{active:kind==='teacher'}]" @click="kind='teacher'"><el-tag>教师使用</el-tag><h2>教师备课包</h2><p>教学设计、课件源码、逐页讲稿、含答案练习与引用清单。</p></article><article :class="['choice',{active:kind==='student'}]" @click="kind='student'"><el-tag type="success">学生使用</el-tag><h2>学生练习包</h2><p>课堂课件与学生练习；不包含讲稿、答案和解析。</p></article></div><el-alert style="margin:18px 0" type="info" :closable="false" title="导出严格对应当前已确认版本，ZIP 不包含密钥、日志或原始上传文件。"/><el-button type="primary" size="large" :loading="working" @click="start">生成 {{kind==='teacher'?'教师':'学生'}} ZIP 包</el-button><a v-if="job?.status==='succeeded'" :href="api.downloadUrl(job.job_id)" class="el-button el-button--success el-button--large" style="margin-left:12px">下载文件</a></div></section></template>

